def update_contract_versions(com_object, log_queue=None):
    """
    Создает или обновляет версии соглашений для всех договоров.
    Сравнивает реквизиты в запросе и обновляет только разницу.
    """
    def log(message, level="info"):
        if log_queue:
            log_queue.put(f"[{level.upper()}] {message}\n")
        verbose_print(f"  {message}")

    try:
        log("Начало процесса обновления версий соглашений договоров...")
        
        query_text = "ВЫБРАТЬ Договор.Ссылка КАК Ссылка, Договор.ВерсияСоглашения КАК ВерсияСоглашения, Договор.ПометкаУдаления КАК ПометкаУдаления ИЗ Справочник.ДоговорыКонтрагентов КАК Договор ЛЕВОЕ СОЕДИНЕНИЕ Документ.ВерсияСоглашенияКоммерческийДоговор КАК Версия ПО (Договор.ВерсияСоглашения = Версия.Ссылка) ГДЕ НЕ Договор.ЭтоГруппа И ДЛИНАСТРОКИ(Договор.Код) > 0 И (Договор.ВерсияСоглашения = НЕОПРЕДЕЛЕНО ИЛИ Договор.ВерсияСоглашения = ЗНАЧЕНИЕ(Документ.ВерсияСоглашенияКоммерческийДоговор.ПустаяСсылка) ИЛИ Договор.АдресОператораПеревода <> Версия.АдресОператораПеревода ИЛИ Договор.АналитикаБДДС1 <> Версия.АналитикаБДДС1 ИЛИ Договор.АналитикаБДДС2 <> Версия.АналитикаБДДС2 ИЛИ Договор.АналитикаБДДС3 <> Версия.АналитикаБДДС3 ИЛИ Договор.АналитикаБДДС4 <> Версия.АналитикаБДДС4 ИЛИ Договор.АналитикаБДДС5 <> Версия.АналитикаБДДС5 ИЛИ Договор.АналитикаБДДС6 <> Версия.АналитикаБДДС6 ИЛИ Договор.АналитикаИсполнение1 <> Версия.АналитикаИсполнение1 ИЛИ Договор.АналитикаИсполнение2 <> Версия.АналитикаИсполнение2 ИЛИ Договор.АналитикаИсполнение3 <> Версия.АналитикаИсполнение3 ИЛИ Договор.АналитикаИсполнение4 <> Версия.АналитикаИсполнение4 ИЛИ Договор.АналитикаИсполнение5 <> Версия.АналитикаИсполнение5 ИЛИ Договор.АналитикаИсполнение6 <> Версия.АналитикаИсполнение6 ИЛИ Договор.АрхивноеДело <> Версия.АрхивноеДело ИЛИ Договор.БазовыйДоговор <> Версия.БазовыйДоговор ИЛИ Договор.БанковскийСчет <> Версия.БанковскийСчет ИЛИ Договор.БанковскийСчетКонтрагента <> Версия.БанковскийСчетКонтрагента ИЛИ Договор.БанковскийСчетТретьеЛицо <> Версия.БанковскийСчетТретьеЛицо ИЛИ Договор.ВалютаВзаиморасчетов <> Версия.ВалютаВзаиморасчетов ИЛИ Договор.ВариантРаздельнойЗакупки <> Версия.ВариантРаздельнойЗакупки ИЛИ Договор.ВидАгентскогоДоговора <> Версия.ВидАгентскогоДоговора ИЛИ Договор.ВидАктива <> Версия.ВидАктива ИЛИ Договор.ВидВзаиморасчетов <> Версия.ВидВзаиморасчетов ИЛИ Договор.ВидДоговораУХ <> Версия.ВидДоговораУХ ИЛИ Договор.ВидДоходаИностранногоКонтрагента <> Версия.ВидДоходаИностранногоКонтрагента ИЛИ Договор.ВидСоглашения <> Версия.ВидСоглашения ИЛИ Договор.ВозможностьПродленияСрокаДействия <> Версия.ВозможностьПродленияСрокаДействия ИЛИ Договор.ВыданноеОбеспечение <> Версия.ВыданноеОбеспечение ИЛИ Договор.ГосударственныйКонтракт <> Версия.ГосударственныйКонтракт ИЛИ Договор.ГрафикДоговора <> Версия.ГрафикДоговора ИЛИ Договор.ДатаНачалаДействия <> Версия.ДатаНачалаДействия ИЛИ Договор.ДатаОплаты <> Версия.ДатаОплаты ИЛИ Договор.ДатаПодписания <> Версия.ДатаПодписания ИЛИ Договор.ДатаПостановкиНаВалютныйКонтроль <> Версия.ДатаПостановкиНаВалютныйКонтроль ИЛИ Договор.ДатаФиксацииКурсаПлатежа <> Версия.ДатаФиксацииКурсаПлатежа ИЛИ Договор.ДлительностьДоставки <> Версия.ДлительностьДоставки ИЛИ Договор.ДоговорПодписан <> Версия.ДоговорПодписан ИЛИ Договор.ДолжностьРуководителя <> Версия.ДолжностьРуководителя ИЛИ Договор.ДолжностьРуководителяКонтрагента <> Версия.ДолжностьРуководителяКонтрагента ИЛИ Договор.ДопустимаяСуммаЗадолженности <> Версия.ДопустимаяСуммаЗадолженности ИЛИ Договор.ЗаРуководителяКонтрагентаПоПриказу <> Версия.ЗаРуководителяКонтрагентаПоПриказу ИЛИ Договор.ЗаРуководителяПоПриказу <> Версия.ЗаРуководителяПоПриказу ИЛИ Договор.ЗапретПлатежаВПрочихВалютах <> Версия.ЗапретПлатежаВПрочихВалютах ИЛИ Договор.ИННОператораПеревода <> Версия.ИННОператораПеревода ИЛИ Договор.ИдентификаторПлатежа <> Версия.ИдентификаторПлатежа ИЛИ Договор.ИспользоватьДатуОплаты <> Версия.ИспользоватьДатуОплаты ИЛИ Договор.ИсточникКурса <> Версия.ИсточникКурса ИЛИ Договор.КлассДоговора <> Версия.КлассДоговора ИЛИ Договор.КодРаздел7ДекларацииНДС <> Версия.КодРаздел7ДекларацииНДС ИЛИ Договор.КоличествоДнейОтсрочкиФакторинга <> Версия.КоличествоДнейОтсрочкиФакторинга ИЛИ Договор.КоличествоЛистов <> Версия.КоличествоЛистов ИЛИ Договор.КоличествоЛистовПриложений <> Версия.КоличествоЛистовПриложений ИЛИ Договор.КомиссияЗаОбработкуСчетаФактуры <> Версия.КомиссияЗаОбработкуСчетаФактуры ИЛИ ПОДСТРОКА(Договор.Комментарий, 0, 200) <> ПОДСТРОКА(Версия.Комментарий, 0, 200) ИЛИ ПОДСТРОКА(Договор.КомментарийДляЕИС, 0, 200) <> ПОДСТРОКА(Версия.КомментарийДляЕИС, 0, 200) ИЛИ Договор.КонтрагентТретьеЛицо <> Версия.КонтрагентТретьеЛицо ИЛИ Договор.Котировка <> Версия.Котировка ИЛИ Договор.КратностьПлатежа <> Версия.КратностьПлатежа ИЛИ Договор.КурсПлатежа <> Версия.КурсПлатежа ИЛИ Договор.КурсПлатежаНеБолее <> Версия.КурсПлатежаНеБолее ИЛИ Договор.КурсПлатежаНеБолееВВалютеОплаты <> Версия.КурсПлатежаНеБолееВВалютеОплаты ИЛИ Договор.КурсПлатежаНеМенее <> Версия.КурсПлатежаНеМенее ИЛИ Договор.КурсПлатежаНеМенееВВалютеОплаты <> Версия.КурсПлатежаНеМенееВВалютеОплаты ИЛИ Договор.НДСПоСтавкам4и2 <> Версия.НДСПоСтавкам4и2 ИЛИ Договор.НаименованиеДляСчетаФактурыНаАванс <> Версия.НаименованиеДляСчетаФактурыНаАванс ИЛИ Договор.НаименованиеОператораПеревода <> Версия.НаименованиеОператораПеревода ИЛИ Договор.НалогообложениеКонтрагента <> Версия.НалогообложениеКонтрагента ИЛИ Договор.ОграничиватьСуммуЗадолженности <> Версия.ОграничиватьСуммуЗадолженности ИЛИ Договор.ОперацияПлатежногоАгента <> Версия.ОперацияПлатежногоАгента ИЛИ Договор.Организация <> Версия.Организация ИЛИ Договор.ОсновнаяВалютаПлатежей <> Версия.ОсновнаяВалютаПлатежей ИЛИ Договор.ОсновнойПроект <> Версия.ОсновнойПроект ИЛИ Договор.ОсновнойЦФО <> Версия.ОсновнойЦФО ИЛИ Договор.Ответственный <> Версия.Ответственный ИЛИ Договор.ПараметрыУчетаФИ <> Версия.ПараметрыУчетаФИ ИЛИ Договор.ПериодРасчетаПени <> Версия.ПериодРасчетаПени ИЛИ Договор.ПлатежныйАгент <> Версия.ПлатежныйАгент ИЛИ Договор.ПолРуководителяКонтрагента <> Версия.ПолРуководителяКонтрагента ИЛИ Договор.ПолученноеОбеспечение <> Версия.ПолученноеОбеспечение ИЛИ Договор.ПорядокРасчетов <> Версия.ПорядокРасчетов ИЛИ Договор.ПорядокРегистрацииСчетовФактурНаАвансПоДоговору <> Версия.ПорядокРегистрацииСчетовФактурНаАвансПоДоговору ИЛИ Договор.ПрекращениеОбязательствСОкончаниемСрокаДействия <> Версия.ПрекращениеОбязательствСОкончаниемСрокаДействия ИЛИ Договор.ПризнакАгента <> Версия.ПризнакАгента ИЛИ Договор.ПриоритетПлатежа <> Версия.ПриоритетПлатежа ИЛИ Договор.Пролонгация <> Версия.Пролонгация ИЛИ Договор.ПроцентАвансаПоФакторингу <> Версия.ПроцентАвансаПоФакторингу ИЛИ Договор.ПроцентКомиссионногоВознаграждения <> Версия.ПроцентКомиссионногоВознаграждения ИЛИ Договор.ПроцентнаяСтавкаПоФакторингу <> Версия.ПроцентнаяСтавкаПоФакторингу ИЛИ Договор.РасчетыВУсловныхЕдиницах <> Версия.РасчетыВУсловныхЕдиницах ИЛИ Договор.РегистрационныйНомерЕИС <> Версия.РегистрационныйНомерЕИС ИЛИ Договор.РежимАктуализацииЗаявок <> Версия.РежимАктуализацииЗаявок ИЛИ Договор.Руководитель <> Версия.Руководитель ИЛИ Договор.РуководительКонтрагента <> Версия.РуководительКонтрагента ИЛИ Договор.РучнойРасчетРезерваПоЗадолженности <> Версия.РучнойРасчетРезерваПоЗадолженности ИЛИ Договор.СдвигДатыФиксацииКурсаПлатежа <> Версия.СдвигДатыФиксацииКурсаПлатежа ИЛИ Договор.СпособВыставленияДокументов <> Версия.СпособВыставленияДокументов ИЛИ Договор.СпособВычисленияДатыФакторинга <> Версия.СпособВычисленияДатыФакторинга ИЛИ Договор.СпособЗаполненияСтавкиНДС <> Версия.СпособЗаполненияСтавкиНДС ИЛИ Договор.СпособОпределенияКурсаПлатежа <> Версия.СпособОпределенияКурсаПлатежа ИЛИ Договор.СпособРасчетаКомиссионногоВознаграждения <> Версия.СпособРасчетаКомиссионногоВознаграждения ИЛИ Договор.СрокДействия <> Версия.СрокДействия ИЛИ Договор.СрокИсполненияПоручения <> Версия.СрокИсполненияПоручения ИЛИ Договор.СрокОплаты <> Версия.СрокОплаты ИЛИ Договор.СрокПогашения <> Версия.СрокПогашения ИЛИ Договор.СрочностьЗадолженности <> Версия.СрочностьЗадолженности ИЛИ Договор.СтавкаНДС <> Версия.СтавкаНДС ИЛИ Договор.СтавкаПени <> Версия.СтавкаПени ИЛИ Договор.СтатьяДвиженияДенежныхСредств <> Версия.СтатьяДвиженияДенежныхСредств ИЛИ Договор.СтраховаяПремия <> Версия.СтраховаяПремия ИЛИ Договор.Сумма <> Версия.Сумма ИЛИ Договор.СуммаНДС <> Версия.СуммаНДС ИЛИ Договор.СчетаФактурыОтИмениОрганизации <> Версия.СчетаФактурыОтИмениОрганизации ИЛИ Договор.ТелефонОператораПеревода <> Версия.ТелефонОператораПеревода ИЛИ Договор.ТелефонОператораПоПриемуПлатежей <> Версия.ТелефонОператораПоПриемуПлатежей ИЛИ Договор.ТелефонПлатежногоАгента <> Версия.ТелефонПлатежногоАгента ИЛИ Договор.ТелефонПоставщика <> Версия.ТелефонПоставщика ИЛИ Договор.ТипЦен <> Версия.ТипЦен ИЛИ Договор.ТребуетсяПостановкаНаУчетВалютногоКонтроля <> Версия.ТребуетсяПостановкаНаУчетВалютногоКонтроля ИЛИ Договор.УИД_ЕИС <> Версия.УИД_ЕИС ИЛИ Договор.УникальныйНомерВалютногоКонтроля <> Версия.УникальныйНомерВалютногоКонтроля ИЛИ Договор.УполномоченныйБанк <> Версия.УполномоченныйБанк ИЛИ Договор.УровеньИерархииСправедливойСтоимости <> Версия.УровеньИерархииСправедливойСтоимости ИЛИ ПОДСТРОКА(Договор.УсловиеНачалаИсполненияДоговора, 0, 200) <> ПОДСТРОКА(Версия.УсловиеНачалаИсполненияДоговора, 0, 200) ИЛИ ПОДСТРОКА(Договор.УсловиеОкончанияИсполненияДоговора, 0, 200) <> ПОДСТРОКА(Версия.УсловиеОкончанияИсполненияДоговора, 0, 200) ИЛИ Договор.УсловиеОплаты <> Версия.УсловиеОплаты ИЛИ Договор.УсловияПоставкиИнкотермс <> Версия.УсловияПоставкиИнкотермс ИЛИ Договор.УстановленСрокОплаты <> Версия.УстановленСрокОплаты ИЛИ Договор.УчетАгентскогоНДС <> Версия.УчетАгентскогоНДС ИЛИ Договор.УчетАгентскогоНДСПокупателем <> Версия.УчетАгентскогоНДСПокупателем ИЛИ Договор.ФайлДоговора <> Версия.ФайлДоговора ИЛИ Договор.ФиксированныйСчетКонтрагента <> Версия.ФиксированныйСчетКонтрагента ИЛИ Договор.ФиксированныйСчетОрганизации <> Версия.ФиксированныйСчетОрганизации ИЛИ Договор.ЭлектронныеУслуги <> Версия.ЭлектронныеУслуги ИЛИ Договор.ЭлектронныйФормат <> Версия.ЭлектронныйФормат ИЛИ Договор.ЯзыкДоговора <> Версия.ЯзыкДоговора ИЛИ Договор.custom_ДатаГарантийногоУдержания <> Версия.custom_ДатаГарантийногоУдержания ИЛИ Договор.custom_НалоговаяОговорка <> Версия.custom_НалоговаяОговорка ИЛИ Договор.custom_ПроцентГарантийногоУдержания <> Версия.custom_ПроцентГарантийногоУдержания ИЛИ Договор.Владелец <> Версия.Контрагент) И Договор.ПометкаУдаления = ЛОЖЬ"
        
        query = com_object.NewObject("Запрос")
        query.Текст = query_text
        
        log("Выполнение запроса...")
        selection = query.Выполнить().Выбрать()
        
        total_to_process = selection.Количество()
        log(f"Найдено договоров для обработки: {total_to_process}")
        
        try:
            current_date = com_object.eval("ТекущаяДата()")
        except:
            current_date = datetime.now()
            
        # Получаем перечисления для режима записи документа
        record_mode_save = None
        record_mode_post = None
        try:
            record_mode_save = com_object.eval("РежимЗаписиДокумента.Запись")
            record_mode_post = com_object.eval("РежимЗаписиДокумента.Проведение")
        except:
            pass

        count_created = 0
        count_updated = 0
        count_errors = 0

        while selection.Следующий():
            contract_ref = selection.Ссылка
            contract_name = str(contract_ref.Наименование)
            version_ref = selection.ВерсияСоглашения
            
            try:
                log(f"Обработка: {contract_name}")
                
                is_new = version_ref is None or version_ref.Пустая()

                if is_new:
                    version_obj = com_object.Документы.ВерсияСоглашенияКоммерческийДоговор.СоздатьДокумент()
                    version_obj.ДоговорКонтрагента = contract_ref
                    count_created += 1
                else:
                    version_obj = version_ref.ПолучитьОбъект()
                    count_updated += 1
                
                # Заполнение всех полей через ЗаполнитьЗначенияСвойств (как в 1С: передаем ссылку, а не объект)
                # Исключаем "Дата, Номер" из копирования
                com_object.ЗаполнитьЗначенияСвойств(version_obj, contract_ref, "", "Дата, Номер")
                
                # Получаем объект договора для установки полей
                contract_obj = contract_ref.ПолучитьОбъект()
                
                # Устанавливаем дату: из договора, если не пустая, иначе текущая дата
                contract_date = current_date
                try:
                    if hasattr(contract_obj, 'Дата'):
                        d = contract_obj.Дата
                        # В 1С через COM пустая дата может быть специфическим объектом
                        # Проверяем на пустоту через встроенную функцию 1С ЗначениеЗаполнено
                        if com_object.ЗначениеЗаполнено(d):
                            contract_date = d
                    
                    version_obj.Дата = contract_date
                except Exception as e_date:
                    log(f"Предупреждение при установке даты: {e_date}", "warn")
                    version_obj.Дата = current_date
                
                # Устанавливаем Контрагент из Владелец договора
                version_obj.Контрагент = contract_obj.Владелец
                
                # Явное присваивание реквизита ВидВзаиморасчетов
                try:
                    if hasattr(contract_obj, 'ВидВзаиморасчетов') and hasattr(version_obj, 'ВидВзаиморасчетов'):
                        version_obj.ВидВзаиморасчетов = contract_obj.ВидВзаиморасчетов
                except:
                    pass
                
                version_obj.ОбменДанными.Загрузка = True
                
                # Записываем версию в режиме обмена данными
                # Для новых версий - проводим (если договор не помечен на удаление)
                # Для существующих версий - только запись, без проведения (как в 1С коде)
                if is_new:
                    # Новая версия - проводим если договор не помечен на удаление
                    need_post = not contract_obj.ПометкаУдаления
                    if record_mode_save and record_mode_post:
                        mode = record_mode_post if need_post else record_mode_save
                        version_obj.Записать(mode)
                    else:
                        version_obj.Записать()
                        if need_post:
                            try:
                                version_obj.Проведен = True
                                version_obj.Записать()
                            except:
                                pass
                else:
                    # Существующая версия - только запись в режиме обмена данными, без проведения
                    if record_mode_save:
                        version_obj.Записать(record_mode_save)
                    else:
                        version_obj.Записать()
                
                # Обновляем ссылку в договоре только если создана новая версия
                if is_new:
                    contract_obj.ВерсияСоглашения = version_obj.Ссылка
                    contract_obj.ОбменДанными.Загрузка = True
                    contract_obj.Записать()
                        
            except Exception as e:
                count_errors += 1
                log(f"Ошибка при обработке {contract_name}: {e}", "error")
        
        log(f"Обновление завершено:")
        log(f"  Создано новых версий: {count_created}")
        log(f"  Обновлено измененных: {count_updated}")
        log(f"  Ошибок: {count_errors}")
        return True

    except Exception as e:
        log(f"Критическая ошибка при обновлении версий: {e}", "error")
        import traceback
        log(traceback.format_exc(), "error")
        return False
